class _CallKitApiCodec extends StandardMessageCodec {
  const _CallKitApiCodec();
  @override
  void writeValue(WriteBuffer buffer, Object? value) {
    if (value is CallConfig) {
      buffer.putUint8(128);
      writeValue(buffer, value.encode());
    } else if (value is CallConfig) {
      buffer.putUint8(129);
      writeValue(buffer, value.encode());
    } else if (value is CallInfo) {
      buffer.putUint8(130);
      writeValue(buffer, value.encode());
    } else if (value is CallParam) {
      buffer.putUint8(131);
      writeValue(buffer, value.encode());
    } else if (value is CallPushConfig) {
      buffer.putUint8(132);
      writeValue(buffer, value.encode());
    } else if (value is CallResponse) {
      buffer.putUint8(133);
      writeValue(buffer, value.encode());
    } else if (value is HangupParam) {
      buffer.putUint8(134);
      writeValue(buffer, value.encode());
    } else if (value is LCKConfig) {
      buffer.putUint8(135);
      writeValue(buffer, value.encode());
    } else if (value is NERtcASRCaptionConfig) {
      buffer.putUint8(136);
      writeValue(buffer, value.encode());
    } else if (value is RtcInfo) {
      buffer.putUint8(137);
      writeValue(buffer, value.encode());
    } else if (value is SetupConfig) {
      buffer.putUint8(138);
      writeValue(buffer, value.encode());
    } else if (value is SignalInfo) {
      buffer.putUint8(139);
      writeValue(buffer, value.encode());
    } else if (value is SimpleResponse) {
      buffer.putUint8(140);
      writeValue(buffer, value.encode());
    } else if (value is SwitchParam) {
      buffer.putUint8(141);
      writeValue(buffer, value.encode());
    } else if (value is UserInfo) {
      buffer.putUint8(142);
      writeValue(buffer, value.encode());
    } else if (value is ViewParam) {
      buffer.putUint8(143);
      writeValue(buffer, value.encode());
    } else {
      super.writeValue(buffer, value);
    }
  }

  @override
  Object? readValueOfType(int type, ReadBuffer buffer) {
    switch (type) {
      case 128: 
        return CallConfig.decode(readValue(buffer)!);
      case 129: 
        return CallConfig.decode(readValue(buffer)!);
      case 130: 
        return CallInfo.decode(readValue(buffer)!);
      case 131: 
        return CallParam.decode(readValue(buffer)!);
      case 132: 
        return CallPushConfig.decode(readValue(buffer)!);
      case 133: 
        return CallResponse.decode(readValue(buffer)!);
      case 134: 
        return HangupParam.decode(readValue(buffer)!);
      case 135: 
        return LCKConfig.decode(readValue(buffer)!);
      case 136: 
        return NERtcASRCaptionConfig.decode(readValue(buffer)!);
      case 137: 
        return RtcInfo.decode(readValue(buffer)!);
      case 138: 
        return SetupConfig.decode(readValue(buffer)!);
      case 139: 
        return SignalInfo.decode(readValue(buffer)!);
      case 140: 
        return SimpleResponse.decode(readValue(buffer)!);
      case 141: 
        return SwitchParam.decode(readValue(buffer)!);
      case 142: 
        return UserInfo.decode(readValue(buffer)!);
      case 143: 
        return ViewParam.decode(readValue(buffer)!);
      default:
        return super.readValueOfType(type, buffer);
    }
