class _GroupCallKitEventSinkCodec extends StandardMessageCodec {
  const _GroupCallKitEventSinkCodec();
  @override
  void writeValue(WriteBuffer buffer, Object? value) {
    if (value is NEGroupCallEndEvent) {
      buffer.putUint8(128);
      writeValue(buffer, value.encode());
    } else if (value is NEGroupCallHangupEvent) {
      buffer.putUint8(129);
      writeValue(buffer, value.encode());
    } else if (value is NEGroupCallInfo) {
      buffer.putUint8(130);
      writeValue(buffer, value.encode());
    } else if (value is NEGroupCallMember) {
      buffer.putUint8(131);
      writeValue(buffer, value.encode());
    } else {
      super.writeValue(buffer, value);
    }
  }

  @override
  Object? readValueOfType(int type, ReadBuffer buffer) {
    switch (type) {
      case 128: 
        return NEGroupCallEndEvent.decode(readValue(buffer)!);
      case 129: 
        return NEGroupCallHangupEvent.decode(readValue(buffer)!);
      case 130: 
        return NEGroupCallInfo.decode(readValue(buffer)!);
      case 131: 
        return NEGroupCallMember.decode(readValue(buffer)!);
      default:
        return super.readValueOfType(type, buffer);
    }
  }
}

