class _GroupMediaEventSinkCodec extends StandardMessageCodec {
  const _GroupMediaEventSinkCodec();
  @override
  void writeValue(WriteBuffer buffer, Object? value) {
    if (value is NEAudioVolumeInfo) {
      buffer.putUint8(128);
      writeValue(buffer, value.encode());
    } else {
      super.writeValue(buffer, value);
    }
  }

  @override
  Object? readValueOfType(int type, ReadBuffer buffer) {
    switch (type) {
      case 128: 
        return NEAudioVolumeInfo.decode(readValue(buffer)!);
      default:
        return super.readValueOfType(type, buffer);
    }
  }
}

